import { Route, Routes } from 'react-router-dom';
import Bebidas from './bebidas';
import BebidasAmpliadas from './bebidas-ampliada';
import Burguers from './burguers';
import BurguersAmpliadas from './burguers-ampliada';
import Combos from './combos';
import CombosAmpliadas from './combos-ampliada';
import './productos.css';


function Productos() {


    return (
        <div >
            <h2 className='productos-h2'>PRODUCTOS</h2>
            <Combos />
            <Burguers />
            <Bebidas />

            <Routes>
                <Route path="/Productos/Combos/:id" element={<CombosAmpliadas />} />

            </Routes>
        </div>
    )
}

export default Productos;
